from collections import Counter, deque

def solve(grid):
    import numpy as np
    inp = np.array(grid)
    H, W = inp.shape

    # Find background (most common) and divider colors
    c = Counter(int(x) for x in inp.flatten())
    bg = c.most_common(1)[0][0]

    # Divider: non-bg color with highest count (much more than markers)
    non_bg = [(color, count) for color, count in c.items() if color != bg]
    non_bg.sort(key=lambda x: -x[1])
    div_color = non_bg[0][0]

    # Find connected regions of non-divider cells (4-connectivity)
    div_mask = (inp == div_color)
    visited = np.zeros((H, W), dtype=bool)
    visited[div_mask] = True

    output = inp.copy()

    for sr in range(H):
        for sc in range(W):
            if visited[sr, sc]:
                continue

            # BFS to find region
            queue = deque([(sr, sc)])
            visited[sr, sc] = True
            cells = set()
            while queue:
                r, cc = queue.popleft()
                cells.add((r, cc))
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    nr, nc = r+dr, cc+dc
                    if 0 <= nr < H and 0 <= nc < W and not visited[nr, nc]:
                        visited[nr, nc] = True
                        queue.append((nr, nc))

            # Find markers
            markers = []
            for r, cc in cells:
                v = int(inp[r, cc])
                if v != bg:
                    markers.append((r, cc, v))

            # Compute Chebyshev distance from boundary
            dist = {}
            bfs_q = deque()
            for r, cc in cells:
                is_boundary = False
                if r == 0 or r == H-1 or cc == 0 or cc == W-1:
                    is_boundary = True
                else:
                    for ddr in [-1, 0, 1]:
                        for ddc in [-1, 0, 1]:
                            if ddr == 0 and ddc == 0:
                                continue
                            nr, nc = r+ddr, cc+ddc
                            if (nr, nc) not in cells:
                                is_boundary = True
                                break
                        if is_boundary:
                            break
                if is_boundary:
                    dist[(r, cc)] = 0
                    bfs_q.append((r, cc))

            while bfs_q:
                r, cc = bfs_q.popleft()
                for ddr in [-1, 0, 1]:
                    for ddc in [-1, 0, 1]:
                        if ddr == 0 and ddc == 0:
                            continue
                        nr, nc = r+ddr, cc+ddc
                        if (nr, nc) in cells and (nr, nc) not in dist:
                            dist[(nr, nc)] = dist[(r, cc)] + 1
                            bfs_q.append((nr, nc))

            if not markers:
                # No markers - fill with background
                for r, cc in cells:
                    output[r, cc] = bg
                continue

            # Build color list from markers
            ring_colors = {}
            for mr, mc, mv in markers:
                d = dist[(mr, mc)]
                ring_colors[d] = mv

            max_ring = max(ring_colors.keys())
            color_list = [ring_colors.get(d, bg) for d in range(max_ring + 1)]

            # Fill region
            for r, cc in cells:
                d = dist[(r, cc)]
                output[r, cc] = color_list[d % len(color_list)]

    return output.tolist()

